const raw = $input.first().json;
const order = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const phone = String(order.phone_e164 || order.phone_local || '').replace(/\D/g, '');
if (!phone) {
  throw new Error('missing_phone_e164');
}
const templateName = $env.META_TEMPLATE_NAME || 'hello_world';
const templateLang = $env.META_TEMPLATE_LANG || 'en_US';
const payload = {
  messaging_product: 'whatsapp',
  to: phone,
  type: 'template',
  template: {
    name: templateName,
    language: { code: templateLang }
  }
};
if (templateName !== 'hello_world') {
  payload.template.components = [
    {
      type: 'body',
      parameters: [
        { type: 'text', text: String(order.customer_name || '') },
        { type: 'text', text: String(order.order_number || '') },
        { type: 'text', text: String(order.items_text || '') },
        { type: 'text', text: String(order.total_mad || '') }
      ]
    },
    {
      type: 'button',
      sub_type: 'quick_reply',
      index: '0',
      parameters: [{ type: 'payload', payload: 'wa_confirm' }]
    },
    {
      type: 'button',
      sub_type: 'quick_reply',
      index: '1',
      parameters: [{ type: 'payload', payload: 'wa_cancel' }]
    },
    {
      type: 'button',
      sub_type: 'quick_reply',
      index: '2',
      parameters: [{ type: 'payload', payload: 'wa_modify' }]
    }
  ];
}
return [{ json: { order, meta_payload: payload, phone, templateName } }];
